chart.options:
chart: {
  type: 'bar',
  height: 350,
  stacked: true,
  toolbar: {
    show: true
  },
  zoom: {
    enabled: true
  }
},
responsive: [{
  breakpoint: 650,
  options: {
    legend: {
      position: 'bottom',
      offsetX: -10,
      offsetY: 0
    }
  }
}],
plotOptions: {
  bar: {
    horizontal: false,
    borderRadius: 10,
    borderRadiusApplication: 'end', // 'around', 'end'
    borderRadiusWhenStacked: 'last', // 'all', 'last'
    dataLabels: {
      total: {
        enabled: true,
        style: {
          fontSize: '13px',
          fontWeight: 900
        }
      }
    }
  },
},
stroke: {
  show: true,
  width: 3
},
title: {
  text: 'Regional Net Sales (outlined columns)',
  align: 'left'
},
dataLabels:{
  style: {
    colors: ['black']
  }
},
xaxis: {
  categories: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
},
yaxis: {
  reversed: false
},
legend: {
  position: 'right',
  offsetY: 40
},
fill: {
  opacity: 0.4
}
